import microcoapy

class CoAPServer:
    def __init__(self):
        self.server = microcoapy.CoAP()
        self.server.add_resource('/sensors/temp', self.handle_temp)
        self.server.add_resource('/actuators/light', self.handle_light)

    def handle_temp(self, packet, sender):
        if packet.code == microcoapy.COAP_CODE['GET']:
            response = microcoapy.Message(microcoapy.COAP_TYPE['ACK'], microcoapy.COAP_CODE['CONTENT'])
            response.payload = b'{"temperature": 22.5}'
            self.server.send_response(sender, response)

    def handle_light(self, packet, sender):
        if packet.code == microcoapy.COAP_CODE['PUT']:
            # Assume payload is a simple "on" or "off" string
            light_state = packet.payload.decode('utf-8')
            if light_state in ['on', 'off']:
                response = microcoapy.Message(microcoapy.COAP_TYPE['ACK'], microcoapy.COAP_CODE['CHANGED'])
                response.payload = f'{{"light": "{light_state}"}}'.encode('utf-8')
                self.server.send_response(sender, response)

    def start(self):
        self.server.listen(5683)

server = CoAPServer()
